import scala.collection.mutable

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  val graph = Array.fill(n)(mutable.ListBuffer[(Int, Long)]())
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val cost = edge(2)
    if (online(u) && online(v)) {
      graph(u).addOne((v, cost))
    }
  }

  var maxScore = -1L
  val minHeap = mutable.PriorityQueue[(Long, Long, Long)]()(Ordering.by(-_._3))
  minHeap.enqueue((0L, 0L, Long.MaxValue)) // (total_cost, node, current_min)

  while (minHeap.nonEmpty) {
    val (total, u, currentMin) = minHeap.dequeue()
    if (u == n - 1) {
      if (total <= k) {
        maxScore = math.max(maxScore, currentMin)
      }
    } else if (total <= k) {
      for ((v, cost) <- graph(u)) {
        val newTotal = total + cost
        val newMin = math.min(currentMin, cost)
        if (newTotal <= k) {
          minHeap.enqueue((newTotal, v.toLong, newMin))
        }
      }
    }
  }

  if (maxScore == -1L) -1L else maxScore
}
