import scala.collection.mutable

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  val graph = mutable.Map[Int, mutable.ListBuffer[(Int, Long)]]().withDefaultValue(mutable.ListBuffer.empty)

  for (edge <- edges) {
    val ui = edge(0).toInt
    val vi = edge(1).toInt
    val cost = edge(2)
    if (online(ui) && online(vi)) {
      graph(ui) += ((vi, cost))
    }
  }

  var left = 0L
  var right = edges.map(_(2)).max
  var result = -1L

  def isValid(minCost: Long): Boolean = {
    val dist = Array.fill(n)(Long.MaxValue)
    dist(0) = 0
    val queue = mutable.PriorityQueue.empty[(Long, Int)](Ordering.by(-_._1))
    queue.enqueue((0L, 0))

    while (queue.nonEmpty) {
      val (currentDist, u) = queue.dequeue()
      if (u == n - 1 && currentDist <= k) return true
      if (currentDist > dist(u)) continue
      for ((v, cost) <- graph(u)) {
        if (cost >= minCost) {
          val newDist = currentDist + cost
          if (newDist < dist(v) && newDist <= k) {
            dist(v) = newDist
            queue.enqueue((newDist, v))
          }
        }
      }
    }
    dist(n - 1) <= k
  }

  while (left <= right) {
    val mid = left + (right - left) / 2
    if (isValid(mid)) {
      result = mid
      left = mid + 1
    } else {
      right = mid - 1
    }
  }

  result
}
